import { useLocation, useNavigate } from "react-router-dom";
import { useState, useMemo } from "react";
import logo from "../assets/logo.png";

export default function Checkout() {
  const location = useLocation();
  const navigate = useNavigate();

  const cart = Array.isArray(location.state?.cart) ? location.state.cart : [];

  const [form, setForm] = useState({
    name: "",
    email: "",
    address: "",
    cardType: "visa",
    cardNumber: "",
    cvv: "",
    expiry: "",
    cardHolder: "",
  });

  const total = useMemo(() => {
    return cart.reduce((sum, item) => {
      const price = Number(item?.price || 0);
      const qty = Number(item?.qty || 0);
      return sum + price * qty;
    }, 0);
  }, [cart]);

  const handleChange = (e) => {
    setForm((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = () => {
    alert("Compra realizada");
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <div style={styles.header}>
          <img src={logo} alt="logo" style={styles.logo} />
          <h2>Checkout</h2>
        </div>

        {cart.length === 0 ? (
          <div style={styles.empty}>
            <p>No hay productos en el carrito.</p>
            <button style={styles.button} onClick={() => navigate("/tienda")}>
              Volver a la tienda
            </button>
          </div>
        ) : (
          <>
            <div style={styles.cartBox}>
              {cart.map((item, index) => (
                <div key={item.id || index} style={styles.row}>
                  <span>
                    {item.name} x {item.qty}
                  </span>
                  <span>
                    $
                    {(Number(item.price || 0) * Number(item.qty || 0)).toFixed(
                      2,
                    )}
                  </span>
                </div>
              ))}
            </div>

            <h3>Total: ${total.toFixed(2)}</h3>

            <div style={styles.form}>
              <input
                name="name"
                placeholder="Nombre"
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="email"
                placeholder="Email"
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="address"
                placeholder="Dirección"
                onChange={handleChange}
                style={styles.input}
              />

              <input
                name="cardHolder"
                placeholder="Titular"
                onChange={handleChange}
                style={styles.input}
              />

              <select
                name="cardType"
                onChange={handleChange}
                style={styles.input}
              >
                <option value="visa">Visa</option>
                <option value="mastercard">MasterCard</option>
                <option value="amex">Amex</option>
              </select>

              <input
                name="cardNumber"
                placeholder="Número"
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="cvv"
                placeholder="CVV"
                onChange={handleChange}
                style={styles.input}
              />
              <input
                name="expiry"
                placeholder="MM/AA"
                onChange={handleChange}
                style={styles.input}
              />

              <div style={styles.buttons}>
                <button onClick={handleSubmit} style={styles.primary}>
                  Confirmar compra
                </button>

                <button
                  onClick={() => navigate("/tienda")}
                  style={styles.secondary}
                >
                  Volver
                </button>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    display: "flex",
    justifyContent: "center",
    padding: "2rem 1rem",
  },

  card: {
    width: "100%",
    maxWidth: "500px",
    background: "white",
    borderRadius: "12px",
    padding: "2rem",
    boxShadow: "0 10px 30px rgba(0,0,0,0.1)",
  },

  header: {
    textAlign: "center",
    marginBottom: "1rem",
  },

  logo: {
    width: "120px",
  },

  cartBox: {
    maxHeight: "180px",
    overflowY: "auto",
    marginBottom: "1rem",
  },

  row: {
    display: "flex",
    justifyContent: "space-between",
    marginBottom: "6px",
  },

  form: {
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  input: {
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #ddd",
  },

  buttons: {
    display: "flex",
    gap: "10px",
    marginTop: "1rem",
  },

  primary: {
    flex: 1,
    padding: "10px",
    background: "#32d5d5",
    color: "white",
    border: "none",
    borderRadius: "8px",
  },

  secondary: {
    flex: 1,
    padding: "10px",
    background: "#e2e8f0",
    border: "none",
    borderRadius: "8px",
  },

  empty: {
    textAlign: "center",
  },

  button: {
    marginTop: "10px",
    padding: "10px",
    background: "#32d5d5",
    border: "none",
    borderRadius: "8px",
    color: "white",
  },
};
